10→export default function Slider(props: Props) {
11→  const ref = useRef<HTMLDivElement>(null);
12→  const [value, setValue] = useState(props.initialValue ?? 0.5);
13→  const draggingRef = useRef(false);
14→
15→  useEffect(() => {
16→    props.renderer.sliders.push({
17→      ref: () => ref.current!,
18→      value: () => value,
19→    });
20→  }, []);
21→
22→  useEffect(() => {
23→    const updateFromEvent = (e: MouseEvent | TouchEvent) => {
24→      if (!ref.current) return;
25→      const rect = ref.current.getBoundingClientRect();
26→      const clientX = 'touches' in e ? (e as TouchEvent).touches[0].clientX : (e as MouseEvent).clientX;
27→      const pct = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
28→      setValue(pct);
29→    };
30→
31→    const onMove = (e: MouseEvent | TouchEvent) => {
32→      if (!draggingRef.current) return;
33→      e.preventDefault();
34→      updateFromEvent(e);
35→    };
36→
37→    const onUp = () => {
38→      draggingRef.current = false;
39→      document.removeEventListener('mousemove', onMove);
40→      document.removeEventListener('mouseup', onUp);
41→      document.removeEventListener('touchmove', onMove);
42→      document.removeEventListener('touchend', onUp);
43→    };
44→
45→    const onDown = (e: MouseEvent | TouchEvent) => {
46→      e.preventDefault();
47→      draggingRef.current = true;
48→      updateFromEvent(e);
49→      document.addEventListener('mousemove', onMove);
50→      document.addEventListener('mouseup', onUp);
51→      document.addEventListener('touchmove', onMove, { passive: false });
52→      document.addEventListener('touchend', onUp);
53→    };
54→
55→    const el = ref.current;
56→    if (el) {
57→      el.addEventListener('mousedown', onDown);
58→      el.addEventListener('touchstart', onDown, { passive: false });
59→    }
60→
61→    return () => {
62→      if (el) {
63→        el.removeEventListener('mousedown', onDown);
64→        el.removeEventListener('touchstart', onDown);
65→      }
66→      document.removeEventListener('mousemove', onMove);
67→      document.removeEventListener('mouseup', onUp);
68→      document.removeEventListener('touchmove', onMove);
69→      document.removeEventListener('touchend', onUp);
70→    };
71→  }, []);
72→
73→  return (
74→    <div className="bar-row">
75→      <span className="bar-label">{props.label}</span>
76→      <div ref={ref} className="wc3-slider">
77→        <img className="slider-bg" src="" alt="" />
78→        <img className="slider-border" src="" alt="" />
79→        <img className="slider-knob" src="" alt="" style={{ left: (value * 100) + '%' }} />
80→      </div>
81→    </div>
82→  );
83→}
